css:
.fx-btn {
  padding: 10px 28px;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  color: #fff;
  cursor: pointer;
  background: linear-gradient(135deg, #3AB54A, #2d9e40, #25a033);
  background-size: 200% 200%;
  animation: gradShift 3s ease infinite;
}
@keyframes gradShift {
  0%,100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.fx-btn-glow {
  padding: 10px 28px;
  background: #3AB54A;
  color: #fff;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  box-shadow: 0 0 15px rgba(58,181,74,0.4), 0 0 30px rgba(58,181,74,0.2);
  transition: box-shadow 0.3s;
}
.fx-btn-glow:hover {
  box-shadow: 0 0 25px rgba(58,181,74,0.4), 0 0 50px rgba(58,181,74,0.3);
}

.fx-btn-ripple {
  padding: 10px 28px;
  background: #3AB54A;
  color: #fff;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  position: relative;
  overflow: hidden;
}
.ripple {
  position: absolute;
  border-radius: 50%;
  background: rgba(255,255,255,0.4);
  transform: scale(0);
  animation: rippleAnim 0.6s ease-out;
}
@keyframes rippleAnim { to { transform: scale(4); opacity: 0; } }

.fx-btn-neon {
  padding: 10px 28px;
  background: transparent;
  border: 2px solid #3AB54A;
  color: #3AB54A;
  font-weight: 600;
  border-radius: 8px;
  cursor: pointer;
  box-shadow: 0 0 10px rgba(58,181,74,0.4), inset 0 0 10px rgba(58,181,74,0.4);
  transition: all 0.3s;
}
.fx-btn-neon:hover {
  background: rgba(58,181,74,0.15);
  box-shadow: 0 0 20px rgba(58,181,74,0.4), inset 0 0 20px rgba(58,181,74,0.4);
}

.fx-btn-slide {
  padding: 10px 28px;
  background: transparent;
  border: 2px solid #3AB54A;
  color: #3AB54A;
  font-weight: 600;
  border-radius: 8px;
  cursor: pointer;
  position: relative;
  z-index: 1;
  overflow: hidden;
}
.fx-btn-slide::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  width: 100%; height: 100%;
  background: #3AB54A;
  z-index: -1;
  transition: left 0.3s;
}
.fx-btn-slide:hover { color: #000; }
.fx-btn-slide:hover::before { left: 0; }

.fx-btn-pulse {
  padding: 10px 28px;
  background: #3AB54A;
  color: #fff;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  animation: btnPulse 2s infinite;
}
@keyframes btnPulse {
  0% { box-shadow: 0 0 0 0 rgba(58,181,74,0.4); }
  70% { box-shadow: 0 0 0 15px rgba(58,181,74,0); }
  100% { box-shadow: 0 0 0 0 rgba(58,181,74,0); }
}

.fx-btn-shadow {
  padding: 10px 28px;
  background: #3AB54A;
  color: #fff;
  font-weight: 600;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s;
}
.fx-btn-shadow:hover {
  box-shadow: 8px 8px 0 rgba(58,181,74,0.5);
  transform: translate(-2px, -2px);
}

.fx-btn-rotate-outline {
  padding: 10px 28px;
  font-weight: 600;
  border: 2px solid transparent;
  color: #3AB54A;
  border-radius: 8px;
  cursor: pointer;
  background-image: linear-gradient(#0d1117, #0d1117), linear-gradient(#3AB54A, #2dd4bf);
  background-origin: border-box;
  background-clip: padding-box, border-box;
  transition: all 0.3s;
}
.fx-btn-rotate-outline:hover {
  background-image: linear-gradient(#0d1117, #0d1117), linear-gradient(#f97316, #ec4899);
}

.spinner {
  width: 40px; height: 40px;
  border: 4px solid #30363d;
  border-top-color: #3AB54A;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

.bounce-dots { display: flex; gap: 8px; }
.bounce-dots span {
  width: 14px; height: 14px;
  background: #3AB54A;
  border-radius: 50%;
  animation: bounce 1.4s infinite ease-in-out both;
}
.bounce-dots span:nth-child(1) { animation-delay: -0.32s; }
.bounce-dots span:nth-child(2) { animation-delay: -0.16s; }
@keyframes bounce {
  0%,80%,100% { transform: scale(0); }
  40% { transform: scale(1); }
}

.square-spin {
  width: 40px; height: 40px;
  background: #3AB54A;
  animation: sqSpin 1.2s ease infinite;
}
@keyframes sqSpin { to { transform: rotate(360deg); } }

.pulse-ring {
  width: 40px; height: 40px;
  border-radius: 50%;
  background: #3AB54A;
  position: relative;
}
.pulse-ring::before, .pulse-ring::after {
  content: '';
  position: absolute;
  inset: -8px;
  border-radius: 50%;
  border: 3px solid #3AB54A;
  animation: pulseRing 1.5s ease-out infinite;
}
.pulse-ring::after { animation-delay: 0.5s; }
@keyframes pulseRing {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(1.3); opacity: 0; }
}

.bar-loader {
  width: 120px; height: 6px;
  background: #30363d;
  border-radius: 3px;
  overflow: hidden;
}
.bar-loader::after {
  content: '';
  display: block;
  width: 40%; height: 100%;
  background: #3AB54A;
  border-radius: 3px;
  animation: barMove 1.5s ease infinite;
}
@keyframes barMove {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(350%); }
}

.flip-loader {
  width: 40px; height: 40px;
  background: #3AB54A;
  animation: flipLoad 1.2s ease infinite;
}
@keyframes flipLoad {
  0% { transform: perspective(160px) rotateX(0); }
  50% { transform: perspective(160px) rotateX(180deg); }
  100% { transform: perspective(160px) rotateX(360deg); }
}

.dot-wave { display: flex; gap: 6px; }
.dot-wave span {
  width: 12px; height: 12px;
  background: #3AB54A;
  border-radius: 50%;
  animation: dotWave 1.2s ease-in-out infinite;
}
.dot-wave span:nth-child(2) { animation-delay: 0.1s; }
.dot-wave span:nth-child(3) { animation-delay: 0.2s; }
.dot-wave span:nth-child(4) { animation-delay: 0.3s; }
.dot-wave span:nth-child(5) { animation-delay: 0.4s; }
@keyframes dotWave {
  0%,100% { transform: translateY(0); }
  50% { transform: translateY(-18px); }
}

.square-spin3d {
  width: 40px; height: 40px;
  background: #3AB54A;
  animation: sqSpin3d 2.4s ease infinite;
}
@keyframes sqSpin3d {
  0% { transform: perspective(120px) rotateX(0) rotateY(0); }
  25% { transform: perspective(120px) rotateX(180deg) rotateY(0); }
  50% { transform: perspective(120px) rotateX(180deg) rotateY(180deg); }
  75% { transform: perspective(120px) rotateX(0) rotateY(180deg); }
  100% { transform: perspective(120px) rotateX(0) rotateY(360deg); }
}

.card-lift {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  padding: 20px;
  transition: all 0.3s;
  cursor: pointer;
}
.card-lift:hover {
  transform: translateY(-8px);
  box-shadow: 0 12px 24px rgba(0,0,0,0.4);
  border-color: #3AB54A;
}

.card-glow {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  padding: 20px;
  transition: all 0.3s;
}
.card-glow:hover {
  border-color: #3AB54A;
  box-shadow: 0 0 20px rgba(58,181,74,0.4), 0 0 40px rgba(58,181,74,0.1);
}

.card-tilt {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  padding: 20px;
  transform-style: preserve-3d;
  transition: transform 0.3s;
  cursor: pointer;
}
/* Add JS: onmousemove rotateX/Y based on mouse position */

.flip-container { perspective: 400px; }
.flip-inner {
  transition: transform 0.6s;
  transform-style: preserve-3d;
}
.flip-container:hover .flip-inner { transform: rotateY(180deg); }
.flip-front, .flip-back {
  backface-visibility: hidden;
  border-radius: 10px;
}
.flip-back {
  transform: rotateY(180deg);
  background: #3AB54A;
}

.card-grad-border {
  position: relative;
  padding: 2px;
  border-radius: 10px;
}
.card-grad-border::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 10px;
  padding: 2px;
  background: linear-gradient(135deg, #3AB54A, #2dd4bf, #f97316);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
}

.card-spotlight {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  padding: 20px;
  position: relative;
  overflow: hidden;
  transition: all 0.3s;
}
.card-spotlight::after {
  content: '';
  position: absolute;
  width: 100px; height: 100px;
  background: radial-gradient(circle, rgba(58,181,74,0.25), transparent 70%);
  border-radius: 50%;
  top: var(--mouse-y, 50%);
  left: var(--mouse-x, 50%);
  transform: translate(-50%, -50%);
  opacity: 0;
  transition: opacity 0.3s;
  pointer-events: none;
}
.card-spotlight:hover::after { opacity: 1; }

.text-gradient {
  font-weight: 700;
  font-size: 2rem;
  background: linear-gradient(135deg, #3AB54A, #2dd4bf, #f97316);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-glitch {
  font-weight: 700;
  color: #e2e8f0;
  animation: glitch 2s infinite;
}
@keyframes glitch {
  0%,100% { text-shadow: none; }
  2% { text-shadow: -2px 0 #ff0040, 2px 0 #00ffff; }
  4% { text-shadow: 2px 0 #ff0040, -2px 0 #00ffff; }
  6% { text-shadow: none; }
}

.text-typewriter {
  font-weight: 700;
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid #3AB54A;
  animation: type 3s steps(12) infinite, blink 0.7s step-end infinite;
  max-width: 200px;
}
@keyframes type {
  0%,10% { width: 0; }
  50%,70% { width: 12ch; }
  90%,100% { width: 0; }
}
@keyframes blink { 50% { border-color: transparent; } }

.text-stroke {
  font-weight: 700;
  -webkit-text-stroke: 2px #3AB54A;
  color: transparent;
}

.text-shadow-stack {
  font-weight: 700;
  color: #e2e8f0;
  text-shadow:
    1px 1px 0 #3AB54A,
    2px 2px 0 rgba(58,181,74,0.8),
    3px 3px 0 rgba(58,181,74,0.6),
    4px 4px 0 rgba(58,181,74,0.4),
    5px 5px 0 rgba(58,181,74,0.2);
}

.text-underline {
  font-weight: 700;
  position: relative;
}
.text-underline::after {
  content: '';
  position: absolute;
  bottom: -4px; left: 0;
  width: 100%; height: 3px;
  background: #3AB54A;
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 0.4s;
}
.text-underline:hover::after {
  transform: scaleX(1);
  transform-origin: left;
}

.text-reveal {
  font-weight: 700;
  position: relative;
  overflow: hidden;
  display: inline-block;
}
.text-reveal::after {
  content: '';
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 100%;
  background: #3AB54A;
  animation: textReveal 3s infinite;
}
@keyframes textReveal {
  0% { transform: translateX(-101%); }
  40% { transform: translateX(0); }
  60% { transform: translateX(0); }
  100% { transform: translateX(101%); }
}

.bg-mesh {
  background:
    radial-gradient(at 20% 30%, rgba(58,181,74,0.4) 0, transparent 50%),
    radial-gradient(at 80% 70%, rgba(45,212,191,0.3) 0, transparent 50%),
    radial-gradient(at 50% 50%, rgba(249,115,22,0.2) 0, transparent 50%),
    #0d1117;
}

.bg-anim-grad {
  background: linear-gradient(-45deg, #3AB54A, #2dd4bf, #f97316, #ec4899);
  background-size: 400% 400%;
  animation: gradBg 6s ease infinite;
}
@keyframes gradBg {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.bg-dots {
  background-image: radial-gradient(circle, #30363d 1px, transparent 1px);
  background-size: 20px 20px;
}

.bg-wave {
  background: linear-gradient(135deg, rgba(58,181,74,0.15), transparent);
  overflow: hidden;
  position: relative;
}
.bg-wave::before {
  content: '';
  position: absolute;
  width: 300%; height: 300%;
  top: -100%; left: -50%;
  background: repeating-radial-gradient(
    circle at 50% 50%,
    transparent 0, transparent 18px,
    rgba(58,181,74,0.08) 19px,
    rgba(58,181,74,0.08) 20px
  );
  animation: waveRotate 20s linear infinite;
}
@keyframes waveRotate { to { transform: rotate(360deg); } }

.bg-geo {
  background-color: #0d1117;
  background-image:
    linear-gradient(30deg, rgba(58,181,74,0.15) 12%, transparent 12.5%, transparent 87%, rgba(58,181,74,0.15) 87.5%),
    linear-gradient(150deg, rgba(58,181,74,0.15) 12%, transparent 12.5%, transparent 87%, rgba(58,181,74,0.15) 87.5%),
    linear-gradient(30deg, rgba(58,181,74,0.15) 12%, transparent 12.5%, transparent 87%, rgba(58,181,74,0.15) 87.5%),
    linear-gradient(150deg, rgba(58,181,74,0.15) 12%, transparent 12.5%, transparent 87%, rgba(58,181,74,0.15) 87.5%);
  background-size: 40px 70px;
  background-position: 0 0, 0 0, 20px 35px, 20px 35px;
}

.hover-scale {
  width: 90px; height: 90px;
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-scale:hover {
  transform: scale(1.15);
  border-color: #3AB54A;
}

.hover-bgslide {
  position: relative;
  overflow: hidden;
  z-index: 1;
  width: 90px; height: 90px;
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-bgslide::before {
  content: '';
  position: absolute;
  inset: 0;
  background: #3AB54A;
  transform: translateY(100%);
  transition: transform 0.3s;
  z-index: -1;
}
.hover-bgslide:hover::before { transform: translateY(0); }
.hover-bgslide:hover { color: #000; border-color: #3AB54A; }

.hover-border-draw {
  position: relative;
  border-color: transparent;
  width: 90px; height: 90px;
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-border-draw:hover {
  border-color: #3AB54A;
  box-shadow: 0 0 10px rgba(58,181,74,0.3);
}

.hover-morph {
  font-size: 2rem;
  color: #8b949e;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-morph:hover {
  color: #3AB54A;
  transform: rotate(180deg) scale(1.2);
}

.hover-colorshift {
  width: 90px; height: 90px;
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-colorshift:hover {
  background: #3AB54A;
  color: #000;
  border-color: #3AB54A;
}

.hover-shadowpop {
  width: 90px; height: 90px;
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 10px;
  transition: all 0.3s;
  cursor: pointer;
}
.hover-shadowpop:hover {
  box-shadow: 0 0 0 4px rgba(58,181,74,0.15), 0 8px 20px rgba(58,181,74,0.3);
  transform: translateY(-4px);
}

@property --angle {
  syntax: '<angle>';
  initial-value: 0deg;
  inherits: false;
}
.border-grad {
  position: relative;
  padding: 2px;
  border-radius: 10px;
}
.border-grad::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 10px;
  padding: 2px;
  background: conic-gradient(from var(--angle), #3AB54A, #2dd4bf, #f97316, #3AB54A);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  animation: gradBorderRotate 3s linear infinite;
}
@keyframes gradBorderRotate { to { --angle: 360deg; } }

.border-dashed {
  border: 3px dashed #3AB54A;
  border-radius: 10px;
  background-image: repeating-linear-gradient(
    45deg, transparent, transparent 10px,
    rgba(58,181,74,0.15) 10px, rgba(58,181,74,0.15) 20px
  );
  background-color: #161b22;
}

.border-double-glow {
  border: 2px solid #3AB54A;
  outline: 2px solid #3AB54A;
  outline-offset: 4px;
  border-radius: 10px;
  background: #161b22;
  box-shadow: 0 0 15px rgba(58,181,74,0.4);
}

.border-corner {
  position: relative;
  border: 1px solid #30363d;
  border-radius: 10px;
  background: #161b22;
}
.border-corner::before, .border-corner::after {
  content: '';
  position: absolute;
  width: 24px; height: 24px;
  border-color: #3AB54A;
  border-style: solid;
}
.border-corner::before {
  top: -1px; left: -1px;
  border-width: 3px 0 0 3px;
  border-radius: 10px 0 0 0;
}
.border-corner::after {
  bottom: -1px; right: -1px;
  border-width: 0 3px 3px 0;
  border-radius: 0 0 10px 0;
}

.input-underline {
  background: transparent;
  border: none;
  border-bottom: 2px solid #30363d;
  color: #e2e8f0;
  padding: 8px 4px;
  font-size: 0.85rem;
  outline: none;
  transition: border-color 0.3s;
}
.input-underline:focus { border-bottom-color: #3AB54A; }

.input-float-group { position: relative; }
.input-float {
  background: transparent;
  border: 1px solid #30363d;
  border-radius: 6px;
  color: #e2e8f0;
  padding: 20px 10px 6px;
  font-size: 0.85rem;
  outline: none;
  width: 100%;
  transition: border-color 0.3s;
}
.input-float:focus { border-color: #3AB54A; }
.input-float-label {
  position: absolute;
  top: 6px; left: 10px;
  font-size: 0.65rem;
  color: #8b949e;
}

.input-glow {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 6px;
  color: #e2e8f0;
  padding: 10px;
  font-size: 0.85rem;
  outline: none;
  transition: all 0.3s;
}
.input-glow:focus {
  border-color: #3AB54A;
  box-shadow: 0 0 10px rgba(58,181,74,0.4);
}

.input-outline {
  background: #161b22;
  border: 2px solid #30363d;
  border-radius: 6px;
  color: #e2e8f0;
  padding: 8px 10px;
  font-size: 0.85rem;
  outline: none;
  transition: all 0.3s;
}
.input-outline:focus {
  border-color: #3AB54A;
  box-shadow: 0 0 0 3px rgba(58,181,74,0.15);
}

.input-filled {
  background: #21262d;
  border: none;
  border-bottom: 2px solid #30363d;
  border-radius: 6px 6px 0 0;
  color: #e2e8f0;
  padding: 12px 10px 8px;
  font-size: 0.85rem;
  outline: none;
  transition: all 0.3s;
}
.input-filled:focus {
  background: #30363d;
  border-bottom-color: #3AB54A;
}

.tooltip-wrap { position: relative; display: inline-flex; }
.tooltip-trigger {
  background: #161b22;
  border: 1px solid #30363d;
  border-radius: 6px;
  color: #e2e8f0;
  padding: 8px 16px;
  cursor: pointer;
}
.tooltip-box {
  position: absolute;
  bottom: calc(100% + 10px);
  left: 50%;
  transform: translateX(-50%) translateY(5px);
  background: #e2e8f0;
  color: #0d1117;
  padding: 6px 12px;
  border-radius: 6px;
  font-size: 0.75rem;
  font-weight: 500;
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: all 0.2s;
}
.tooltip-box::after {
  content: '';
  position: absolute;
  top: 100%; left: 50%;
  transform: translateX(-50%);
  border: 5px solid transparent;
  border-top-color: #e2e8f0;
}
.tooltip-wrap:hover .tooltip-box {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

.accordion {
  border: 1px solid #30363d;
  border-radius: 8px;
  overflow: hidden;
}
.accordion-header {
  padding: 10px 12px;
  background: #161b22;
  cursor: pointer;
  font-weight: 600;
  display: flex;
  justify-content: space-between;
}
.accordion-body {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s, padding 0.3s;
  padding: 0 12px;
  font-size: 0.8rem;
  color: #8b949e;
}
.accordion-header.open + .accordion-body {
  max-height: 100px;
  padding: 10px 12px;
}

.checkbox-wrap {
  display: flex; align-items: center; gap: 10px;
  cursor: pointer;
}
.checkbox-wrap input { display: none; }
.checkbox-box {
  width: 22px; height: 22px;
  border: 2px solid #30363d;
  border-radius: 5px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}
